1	/**
2	 * POST /api/upload/signed/prepare
3	 *
4	 * Step 1 of 2 for the direct-to-storage upload flow. Works for ANY
5	 * supported file type — audio, PDF, DOCX, text, transcripts — not
6	 * just audio. The client POSTs metadata only, we:
7	 *
8	 *   1. validate auth + size against the `MAX_UPLOAD_BYTES` cap
9	 *      (default 500 MB);
10	 *   2. create an Upload row in `status='pending'` with storage
11	 *      placeholders;
12	 *   3. mint a one-shot signed-upload URL on Supabase Storage so the
13	 *      client can PUT the bytes directly, bypassing Vercel's 4.4 MB
14	 *      serverless body cap;
15	 *   4. return `{ uploadId, signedUrl, publicUrl, objectPath, isAudio }`.
16	 *
17	 * The client PUTs the file to `signedUrl` from the browser (getting
18	 * live progress via XHR), then calls
19	 * `/api/upload/signed/finalize/[id]`.
20	 *
21	 * This is the successor to the audio-only
22	 * `/api/upload/audio/prepare` endpoint. The old path is still
23	 * registered as a thin shim (see its route.ts) so Dialectic / other
24	 * external callers that hard-coded it don't break during rollout.
25	 *
26	 * If Supabase Storage isn't configured (SUPABASE_URL or
27	 * SUPABASE_SERVICE_ROLE_KEY missing), returns 501 so the client
28	 * falls back to the inline `/api/upload` path for small files.
29	 */
30	import { NextResponse } from "next/server";
31	import { getFounderFromAuth } from "@/lib/apiKeyAuth";
32	import { db } from "@/lib/db";
33	import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
34	import { sanitizeText, sanitizeAndCap } from "@/lib/sanitizeText";
35	import { pickAvailableSlug } from "@/lib/slugify";
36	import {
37	  createSignedAudioUploadUrl,
38	  ensureAudioBucketCapacity,
39	  getAudioBucket,
40	  isAudioStorageConfigured,
41	} from "@/lib/supabaseStorage";
42	
43	/**
44	 * Hard cap. Defaults to 500 MB so podcast episodes comfortably fit —
45	 * a 2-hour MP3 at 128 kbps is ~115 MB, a 2-hour WAV is ~1.2 GB
46	 * (trim it first). Override via env for heavier files, but note
47	 * that Supabase Storage also has its own per-file size limit
48	 * configured in the bucket settings — both need to permit the
49	 * upload for it to succeed. We read `MAX_UPLOAD_BYTES` first, then
50	 * fall back to the legacy `MAX_AUDIO_BYTES` name for anyone who
51	 * already set the old env var.
52	 */
53	const MAX_UPLOAD_BYTES = Number(
54	  process.env.MAX_UPLOAD_BYTES ||
55	    process.env.MAX_AUDIO_BYTES ||
56	    500 * 1024 * 1024,
57	);
58	
59	// Same allow-list the inline /api/upload enforces, plus .aac which
60	// modern podcast pipelines sometimes emit.
61	const ALLOWED_EXT = new Set([
62	  ".md",
63	  ".markdown",
64	  ".txt",
65	  ".vtt",
66	  ".jsonl",
67	  ".json",
68	  ".pdf",
69	  ".docx",
70	  ".mp3",
71	  ".m4a",
72	  ".wav",
73	  ".webm",
74	  ".ogg",
75	  ".aac",
76	]);
77	
78	const AUDIO_EXTS = new Set([
79	  ".mp3",
80	  ".m4a",
81	  ".wav",
82	  ".webm",
83	  ".ogg",
84	  ".aac",
85	]);
86	
87	function lowerExt(filename: string): string {
88	  const i = filename.lastIndexOf(".");
89	  return i >= 0 ? filename.slice(i).toLowerCase() : "";
90	}
91	
92	export async function POST(req: Request) {
93	  try {
94	    const founder = await getFounderFromAuth(req);
95	    if (!founder) {
96	      return NextResponse.json(
97	        { error: "Not authenticated" },
98	        { status: 401 },
99	      );
100	    }
101	    // Role gate: viewers don't get to mint signed URLs either. Without
102	    // this check the bucket would happily accept a viewer's PUT once
103	    // we'd handed them the signed URL, since the URL itself carries
104	    // the auth.
105	    if (!canWrite(founder.role)) {
106	      return NextResponse.json(WRITE_FORBIDDEN_RESPONSE, { status: 403 });
107	    }
108	
109	    if (!isAudioStorageConfigured()) {
110	      return NextResponse.json(
111	        {
112	          error:
113	            "Direct upload needs Supabase Storage. Set SUPABASE_URL + " +
114	            "SUPABASE_SERVICE_ROLE_KEY on Vercel and redeploy, or fall " +
115	            "back to /api/upload for files under 3.5 MB. See " +
116	            "docs/Auto_Processing_Setup.md for the walkthrough.",
117	        },
118	        { status: 501 },
119	      );
120	    }
121	
122	    const body = (await req.json().catch(() => ({}))) as {
123	      filename?: string;
124	      mimeType?: string;
125	      size?: number;
126	      // Dialectic (and anything scripted) historically used `fileSize`
127	      // for the byte count. Accept either so old callers keep working.
128	      fileSize?: number;
129	      title?: string;
130	      description?: string;
131	      sourceType?: string;
132	      visibility?: string;
133	      publishAsPost?: boolean;
134	      blogExcerpt?: string;
135	      authorBio?: string;
136	      audioDurationSec?: number;
137	      // Dialectic pre-computes a transcript before uploading the
138	      // trimmed .wav, so the Codex can skip Whisper entirely and jump
139	      // straight to claim extraction. When present, `textContent` is
140	      // seeded at prepare-time and `status` starts at `awaiting_ingest`
141	      // — finalize just persists the audio file reference on top.
142	      transcript?: string;
143	      extractionMethod?: string;
144	      recordedDate?: string;
145	    };
146	
147	    const filename = (body.filename || "").trim();
148	    const size = Number(body.size || body.fileSize || 0);
149	    const mimeType = (body.mimeType || "").toLowerCase();
150	
151	    if (!filename) {
152	      return NextResponse.json(
153	        { error: "filename is required" },
154	        { status: 400 },
155	      );
156	    }
157	    if (!size || !Number.isFinite(size) || size <= 0) {
158	      return NextResponse.json(
159	        { error: "size (bytes) is required and must be positive" },
160	        { status: 400 },
161	      );
162	    }
163	    if (size > MAX_UPLOAD_BYTES) {
164	      return NextResponse.json(
165	        {
166	          error:
167	            `File is ${(size / 1024 / 1024).toFixed(1)} MB — exceeds the ` +
168	            `${(MAX_UPLOAD_BYTES / 1024 / 1024).toFixed(0)} MB cap. Trim ` +
169	            `the file or raise MAX_UPLOAD_BYTES on Vercel. Note: ` +
170	            `Supabase also has a per-file "File size limit" in the ` +
171	            `bucket settings — raise that too.`,
172	        },
173	        { status: 413 },
174	      );
175	    }
176	
177	    // Supabase buckets enforce a per-file cap in addition to our
178	    // app-level MAX_UPLOAD_BYTES. When the bucket cap is lower than
179	    // the incoming file, Supabase rejects the direct PUT mid-flight
180	    // with a 413 "Payload too large" and the user sees a confusing
181	    // failure after a long upload wait.
182	    //
183	    // `ensureAudioBucketCapacity` fixes this by PATCH-ing the bucket
184	    // to raise its `file_size_limit` to at least the incoming file
185	    // size (defaulting to 500 MB so small-then-big upload sequences
186	    // don't trigger a raise every request). The service-role key has
187	    // admin privileges to do this. Earlier versions of this route
188	    // called `getAudioBucketFileSizeLimitBytes` and returned 413 if
189	    // the cap was lower — but if the bucket had no cap set at all
190	    // (common default), the read returned `null`, we skipped the
191	    // check, and the user hit the same Supabase-side 413 anyway.
192	    const ensure = await ensureAudioBucketCapacity(size);
193	    if (!ensure.ok) {
194	      const sizeMb = (size / 1024 / 1024).toFixed(1);
195	      let message: string;
196	      if (ensure.reason === "unconfigured") {
197	        message =
198	          "Supabase Storage is not configured on the server. Set " +
199	          "SUPABASE_URL + SUPABASE_SERVICE_ROLE_KEY on Vercel and " +
200	          "redeploy, then retry the upload.";
201	      } else if (ensure.reason === "plan_limit") {
202	        // The plan-level ceiling is the usual culprit here. On the
203	        // free tier it's 50 MB; on Pro it's 5 GB. The Storage API
204	        // refuses to let us raise the bucket's `file_size_limit`
205	        // above the plan ceiling even as a service-role request —
206	        // so if both the generous 500 MB target AND the exact file
207	        // size get rejected, the file genuinely exceeds what the
208	        // plan permits. We can't fix this in code; the user needs
209	        // to change one of: the file's size, the Supabase plan,
210	        // or (eventually) the storage backend itself.
211	        message =
212	          `Upload is ${sizeMb} MB, but your Supabase plan refuses ` +
213	          `to accept files that big. On the free tier the per-file ` +
214	          `ceiling is 50 MB; on Pro it rises to 5 GB. Three ways out:\n` +
215	          `  • Upgrade Supabase (Pro is $25/mo, ceiling becomes 5 GB): ` +
216	          `https://supabase.com/dashboard/project/_/settings/billing\n` +
217	          `  • Compress the audio below 50 MB — for an ~2 hour podcast, ` +
218	          `\`ffmpeg -i input.m4a -b:a 32k -ac 1 output.m4a\` usually ` +
219	          `lands around 30 MB.\n` +
220	          `  • Split into parts: ` +
221	          `\`ffmpeg -i input.m4a -f segment -segment_time 3600 -c copy part%d.m4a\` ` +
222	          `and upload each piece separately.`;
223	      } else {
224	        const detailSuffix = ensure.detail
225	          ? ` Supabase response: ${ensure.detail.slice(0, 200)}`
226	          : "";
227	        message =
228	          `Couldn't raise the Supabase bucket size limit to accept ` +
229	          `this ${sizeMb} MB file, and the failure isn't the usual ` +
230	          `plan-ceiling signal. Raise Storage → Bucket settings → ` +
231	          `File size limit manually, or check the SUPABASE_SERVICE_ROLE_KEY ` +
232	          `scope.${detailSuffix}`;
233	      }
234	      return NextResponse.json({ error: message }, { status: 413 });
235	    }
236	
237	    const ext = lowerExt(filename);
238	    const isAudio =
239	      mimeType.startsWith("audio/") || AUDIO_EXTS.has(ext);
240	
241	    if (!ALLOWED_EXT.has(ext) && !isAudio) {
242	      return NextResponse.json(
243	        {
244	          error:
245	            `Unsupported file type (${ext || mimeType || "unknown"}). ` +
246	            `Allowed: ${[...ALLOWED_EXT].join(", ")}.`,
247	        },
248	        { status: 400 },
249	      );
250	    }
251	
252	    // Visibility / publish parsing — same three-level contract as
253	    // /api/upload. See Upload.visibility in schema.prisma for the full
254	    // semantics of each level.
255	    const rawVisibility = (body.visibility || "org").toLowerCase();
256	    const visibility: "org" | "semi-private" | "private" =
257	      rawVisibility === "private"
258	        ? "private"
259	        : rawVisibility === "semi-private"
260	          ? "semi-private"
261	          : "org";
262	    const publishAsPost = Boolean(body.publishAsPost);
263	    if (visibility !== "org" && publishAsPost) {
264	      return NextResponse.json(
265	        {
266	          error:
267	            visibility === "private"
268	              ? "An upload can't be both private and published as a blog post. Choose one."
269	              : "An upload can't be both semi-private and published as a blog post. Choose one.",
270	        },
271	        { status: 400 },
272	      );
273	    }
274	
275	    // ── Sanitize + persist minimal metadata on the Upload row.
276	    const safeTitle =
277	      sanitizeText(
278	        (body.title && String(body.title).trim()) ||
279	          filename.replace(/\.[^/.]+$/, ""),
280	      ).slice(0, 500) || "Untitled upload";
281	    const safeDescription = sanitizeAndCap(body.description || "", 10_000);
282	    const safeOriginalName = sanitizeText(filename).slice(0, 500);
283	    const safeMime =
284	      sanitizeText(mimeType || "application/octet-stream").slice(0, 255) ||
285	      "application/octet-stream";
286	
287	    // Build a deterministic object path: <upload-id>/<filename-slug>.ext
288	    // We need the upload id BEFORE creating the row so the signed URL
289	    // can embed it. Prisma's `@default(cuid())` runs at insert time,
290	    // which is too late — so we mint a collision-resistant id from
291	    // Node's crypto primitives and pass it explicitly into create().
292	    const { randomBytes } = await import("crypto");
293	    const uploadId = "c" + randomBytes(14).toString("hex").slice(0, 24);
294	    const safeFilenamePart = filename.replace(/[^A-Za-z0-9._-]+/g, "_");
295	    const objectPath = `${uploadId}/${safeFilenamePart}`;
296	
297	    const handle = await createSignedAudioUploadUrl(objectPath);
298	    if (!handle) {
299	      return NextResponse.json(
300	        { error: "Could not mint a signed upload URL." },
301	        { status: 500 },
302	      );
303	    }
304	
305	    // Publish fields, only if requested and visibility allows.
306	    let publishFields: {
307	      publishedAt: Date;
308	      slug: string;
309	      blogExcerpt: string | null;
310	      authorBio: string | null;
311	    } | null = null;
312	    if (publishAsPost) {
313	      const slug = await pickAvailableSlug(safeTitle, async (candidate) => {
314	        const existing = await db.upload.findUnique({
315	          where: { slug: candidate },
316	          select: { id: true },
317	        });
318	        return existing !== null;
319	      });
320	      publishFields = {
321	        publishedAt: new Date(),
322	        slug,
323	        blogExcerpt: body.blogExcerpt
324	          ? sanitizeAndCap(body.blogExcerpt, 400)
325	          : null,
326	        authorBio: body.authorBio
327	          ? sanitizeAndCap(body.authorBio, 160)
328	          : null,
329	      };
330	    }
331	
332	    const duration =
333	      isAudio &&
334	      body.audioDurationSec &&
335	      Number.isFinite(body.audioDurationSec)
336	        ? Math.max(0, Math.floor(body.audioDurationSec))
337	        : null;
338	
339	    // Dialectic pre-attaches the transcript. When present, we seed
340	    // `textContent` now so `ingest-from-codex` can skip Whisper and run
341	    // only claim extraction; the status jumps straight to
342	    // `awaiting_ingest` so the dashboard reflects that extraction is
343	    // already done before the bytes even land.
344	    const preAttachedTranscript =
345	      typeof body.transcript === "string" && body.transcript.trim().length > 0
346	        ? sanitizeAndCap(body.transcript, 2_000_000)
347	        : null;
348	    const preAttachedExtraction =
349	      typeof body.extractionMethod === "string" && body.extractionMethod.trim()
350	        ? sanitizeText(body.extractionMethod).slice(0, 64)
351	        : null;
352	    const resolvedSourceType = sanitizeText(
353	      body.sourceType ||
354	        (preAttachedTranscript ? "transcript" : isAudio ? "audio" : "written"),
355	    ).slice(0, 64);
356	    const initialStatus = preAttachedTranscript ? "awaiting_ingest" : "pending";
357	
358	    const upload = await db.upload.create({
359	      data: {
360	        id: uploadId,
361	        organizationId: founder.organizationId,
362	        founderId: founder.id,
363	        title: safeTitle,
364	        description: safeDescription,
365	        sourceType: resolvedSourceType,
366	        originalName: safeOriginalName,
367	        mimeType: safeMime,
368	        filePath: `storage:${objectPath}`,
369	        fileSize: size,
370	        textContent: preAttachedTranscript,
371	        extractionMethod: preAttachedExtraction,
372	        status: initialStatus,
373	        processLog: sanitizeAndCap(
374	          `— Direct upload reserved (${(size / 1024 / 1024).toFixed(1)} MB) —\n` +
375	            `— Awaiting client PUT to Supabase Storage —\n` +
376	            (preAttachedTranscript
377	              ? `— Transcript pre-attached (${preAttachedTranscript.length} chars, ` +
378	                `method=${preAttachedExtraction ?? "unspecified"}); ` +
379	                `server-side extraction will be skipped —\n`
380	              : ""),
381	          8_000,
382	        ),
383	        visibility,
384	        // audioUrl is only set for audio rows, and only after the
385	        // PUT actually lands (in /finalize). Non-audio rows keep it
386	        // null.
387	        audioUrl: null,
388	        audioDurationSec: duration,
389	        ...(publishFields ?? {}),
390	      },
391	    });
392	
393	    await db.auditEvent
394	      .create({
395	        data: {
396	          organizationId: founder.organizationId,
397	          founderId: founder.id,
398	          uploadId: upload.id,
399	          action: "signed_upload_reserved",
400	          detail:
401	            `Reserved ${isAudio ? "audio" : "file"} slot for ${safeOriginalName} ` +
402	            `(${(size / 1024 / 1024).toFixed(1)} MB) at ${objectPath}`,
403	        },
404	      })
405	      .catch(() => {
406	        /* non-fatal */
407	      });
408	
409	    return NextResponse.json({
410	      uploadId: upload.id,
411	      signedUrl: handle.signedUrl,
412	      token: handle.token,
413	      publicUrl: handle.publicUrl,
414	      objectPath,
415	      isAudio,
416	      // The client includes these in its PUT so Supabase accepts it
417	      // cleanly regardless of the browser's default Content-Type
418	      // inference.
419	      headers: {
420	        "Content-Type": safeMime,
421	      },
422	    });
423	  } catch (err) {
424	    console.error("upload/signed/prepare error:", err);
425	    return NextResponse.json(
426	      {
427	        error: `Could not prepare upload: ${err instanceof Error ? err.message : "unknown error"}`,
428	      },
429	      { status: 500 },
430	    );
431	  }
432	}
